function isValidDepth(s, maxDepth) {
  const stack = [];
  const pairs = { ')': '(', ']': '[', '}': '{' };
  for (const ch of s) {
    if ('([{'.includes(ch)) {
      stack.push(ch);
      if (stack.length > maxDepth) return false;
      continue;
    }
    if (stack.pop() !== pairs[ch]) return false;
  }
  return stack.length === 0;
}
